Which is the graph of $y = f(x) - 1$?

[asy]
unitsize(0.5 cm);

picture[] graf;
int i, n;

real func(real x) {
  real y;
  if (x >= -3 && x <= 0) {y = -2 - x;}
  if (x >= 0 && x <= 2) {y = sqrt(4 - (x - 2)^2) - 2;}
  if (x >= 2 && x <= 3) {y = 2*(x - 2);}
  return(y);
}

real funca(real x) {
  return(func(x) + 1);
}

real funcc(real x) {
  return(func(x) - 1);
}

for (n = 1; n <= 5; ++n) {
  graf[n] = new picture;
