draw(graf[3],graph(funcc,-3,3),red);
draw(graf[4],shift((-1,-1))*graph(func,-3,3),red);
draw(graf[5],shift((-1,-1))*graph(func,-3,3),red);

label(graf[1], "A", (0,-6));
label(graf[2], "B", (0,-6));
